head.script:
scwin.onpageload = function () {

    grp_infoBox.setReadOnly(true);

    const {CargoType,idx} = $c.data.getParameter();

    scwin.cargoType = CargoType;

    if ($c.util.isEmpty(idx)) {
        scwin.idxs = "0-0".split("-");
    } else {
        scwin.idxs = idx.split("-");
    }

    // master번호
    scwin.m = scwin.idxs[0];

    const info = {};
    if (scwin.cargoType == "cargo") {
        info.index = 0;
        info.value = "blk";
        scwin.showHideLayer(info);
    } else {
        info.index = 1;
        info.value = "cntr";
        scwin.showHideLayer(info);
    }

    const codeOptions = [
        {method: "getComboDTOArray",param1: "UNIT",param2: $c.data.getMemInfo("userId"),compID: "lc_unit"}
    ];
    $c.data.setCommonComboUtil(codeOptions);

};

/**
 * data onload
 */
scwin.ondataload = function() {

    wfm_header.getWindow().txt_h1.options.escape = false;
    const pTitle = "<span style='color: #ff0022'>[조회]</span> 화물상세정보"
    $c.data.setPopupTitle(pTitle);
    scwin.retrieveCarnfo();
};

/**
 * 조회
 */
scwin.retrieveCarnfo = async function () {

    // master번호가 있으면 조회
    if ((!scwin.idxs[0] == "0") && (!scwin.idxs[0] == "")) {

        let ret = "";

        // 화주 검색
        const strParam = {
            ez202Idx: scwin.idxs[0] // 시스템코드
        };

        dma_master.setEmptyValue();
        dma_master.setJSON(strParam);
        ret = await $c.sbm.execute(sbm_master);
        if (ret.responseJSON.resultDataSet[0].Code == 0) {
            ds_master.setJSON(ret.responseJSON.GAUCE);
        }

        // 화물내용 검색
        const strParam1 = {
              idx1: scwin.idxs[0]
            , idx2: scwin.idxs[1]
        };

        dma_cargo.setEmptyValue();
        dma_cargo.setJSON(strParam1);

        if (scwin.cargoType == "cargo") {
            $c.sbm.setAction(sbm_cargo, "/ncall.bp.fbp.op.ac.cmd.RetrieveBlkInfoCMD.do")
        } else if (scwin.cargoType == "cont") {
            $c.sbm.setAction(sbm_cargo, "/ncall.bp.fbp.op.ac.cmd.RetrieveCntrInfoCMD.do")
        }

        ret = await $c.sbm.execute(sbm_cargo)
        if (ret.responseJSON.resultDataSet[0].Code == 0) {
            ds_cargo.setJSON(ret.responseJSON.GAUCE)
        }

    }
};

/**
 * 화물내용 ondataload
 */
scwin.ds_cargo_ondataload = function () {

    tbx_totalRows.setValue(ds_cargo.getRowCount());

    if (ds_cargo.getRowCount() > 0) {

        gr_cargo.setFocusedCell(0, "cargoIdx");
        // ds_cargo.setRowPosition(0);

    }

};

/**
 * show / hide
 */
scwin.showHideLayer = function (info) {

    if (info.value == "blk") {
        // bulk
        rd_cargoType1.setValue("blk");
        rd_cargoType2.setValue("");

        grp_cntrBox.setStyle("display", "none");     // 컨테이너정보

        // 그리드
        gr_cargo.setColumnVisible("ez112Idx", false); // 거래처코드
        gr_cargo.setColumnVisible("cstmclrncCmis", false);       // 통관료
        gr_cargo.setColumnVisible("onCmis", false);      // 상차료
        gr_cargo.setColumnVisible("offCmis", false);     // 하차료
        gr_cargo.setColumnVisible("shpCo", false);       // 선사명
        gr_cargo.setColumnVisible("shpNm", false);       // 선박명항차
        gr_cargo.setColumnVisible("portNo", false);      // 포트
        gr_cargo.setColumnVisible("cntrBookingNo", false);       // 부킹/BL
        gr_cargo.setColumnVisible("cntrOrdNo", false);       // 동부ORDNO
        gr_cargo.setColumnVisible("cntrNo", false);      // 컨테이너번호
        gr_cargo.setColumnVisible("cntrSealNo", false);      // 실번호
        gr_cargo.setColumnVisible("cntrSiz", false);     // 컨테이너사이즈
        gr_cargo.setColumnVisible("cntrCloseDt", false);     // 컨테이너마감일
        gr_cargo.setColumnVisible("emptyFull", false);       // EMPTYFULL
        gr_cargo.setColumnVisible("cyCmis", false);      // cy수수료
        gr_cargo.setColumnVisible("payCmisPayfor", false);       // 상차료대납여부
        gr_cargo.setColumnVisible("onCmisBilgFareInc", false);       // 상차료청구운임에 포함
        gr_cargo.setColumnVisible("payHndlCmis", false);     // 기타료


    } else {

        // container
        rd_cargoType1.setValue("");
        rd_cargoType2.setValue("cntr");

        tbl_apDiv6.setStyle("display", "none");     // 벌크 운송운임 계산
        tbl_blkDt1.setStyle("display", "none");     // 화물정보

        // binding 변경
        ed_m12.setRef("data:ds_cargo.onDd");    // 상차일자
        ed_m16.setRef("data:ds_cargo.offDd");   // 하차일자

        gr_cargo.setColumnVisible("fareCalcTyp", false);	  // 운임계산방법
        gr_cargo.setColumnVisible("goods", false);	  // 품명
        gr_cargo.setColumnVisible("unit", false);	  // 단위
        gr_cargo.setColumnVisible("qty", false);	  // 수량
        gr_cargo.setColumnVisible("nrm", false);	  // CBM
        gr_cargo.setColumnVisible("initAmt", false);	  // 선수금
        gr_cargo.setColumnVisible("prePayAmt", false);	  // 선급금
        gr_cargo.setColumnVisible("cntrCloseDt", false);     // 컨테이너마감일

        // 중량 컬럼 위치 변경
        const arr = gr_cargo.getColumnOrder(true);
        const idx = arr.indexOf("wt");
        if (idx !== -1) {
            arr.splice(idx, 1);
        }
        arr.push("wt");
        gr_cargo.setColumnOrder(arr);

    }

    scwin.setButton("none");
};

/**
 * button setting
 */
scwin.setButton = function (flag) {
    btn_consNm.setStyle("display", flag);
    btn_allAddr.setStyle("display", flag);
    btn_allAddr2.setStyle("display", flag);
    btn_clntNm.setStyle("display", flag);
};

/**
 * grid display formatter - 화물티입
 */
scwin.displayCargoType = function (data) {
    return $c.gus.decode(data, "blk", "벌크", "컨테이너");
};

/**
 * grid display formatter - 상차요청시간 / 하차요청시간
 */
scwin.format_time = function(val) {
    return `${val.slice(0,2)}:${val.slice(2,4)}`;
};

/**
 * grid display formatter - emptyFull
 */
scwin.format_emptyFull = function(val) {
    return val == 0 ? "E" : "F";
};

/**
 * grid display formatter - 상차료대납여부 / 상차료청구운임에 포함
 */
scwin.format_YN = function(val) {
    return val == 1 ? "O" : "X";
};
